#include<bits/stdc++.h>
#define int long long
using namespace std;
const int MAXN = 2e3 + 10;
int a[MAXN], dp[MAXN][MAXN], sum[MAXN];//dp[i][j] 为 第一个人从i到j的最优解 
signed main()
{
	int n;
	cin >> n;
	for(int i = 1; i <= n; i++){
		cin >> a[i];
		dp[i][i] = a[i];
		sum[i] = sum[i - 1] + a[i];
	}
	for(int i = n - 1; i >= 1; i--)
		for(int j = i + 1; j <= n; j++)
			dp[i][j] = max(sum[j] - sum[i - 1] - dp[i + 1][j], sum[j] - sum[i - 1] - dp[i][j - 1]);
//	从i到j，第一人的最优解   a[i]到a[j]的sum      选左边，左边界 + 1              选右边，右边界 + 1  
	cout << dp[1][n] << " " << sum[n] - dp[1][n];
}
